INSERT INTO capability_levels (capability_id, level, description) SELECT id, 'foundational', 'Takes responsibility for assigned tasks. Follows through on commitments with reminders. Acknowledges mistakes when pointed out. May make excuses or blame external factors when things go wrong. Learning to proactively track and report on commitments. Meets most deadlines with support and follow-up.' FROM capabilities WHERE name = 'Accountability' ON CONFLICT DO NOTHING;
INSERT INTO capability_levels (capability_id, level, description) SELECT id, 'advancing', 'Consistently delivers on commitments without reminders. Proactively communicates if deadlines or deliverables are at risk. Tracks own commitments and follows through independently. Delivers quality work on time consistently. Holds others accountable in peer situations. Known as reliable and dependable.' FROM capabilities WHERE name = 'Accountability' ON CONFLICT DO NOTHING;
INSERT INTO capability_levels (capability_id, level, description) SELECT id, 'independent', 'Takes full ownership of outcomes, not just activities. Holds self accountable to the highest standards. Addresses problems proactively rather than waiting for others to notice. Delivers results even in challenging circumstances. Creates culture of accountability on teams. Known for being someone you can count on completely. Takes accountability without making excuses.' FROM capabilities WHERE name = 'Accountability' ON CONFLICT DO NOTHING;
INSERT INTO capability_levels (capability_id, level, description) SELECT id, 'mastery', 'Drives accountability as an organizational capability. Holds the most senior leaders accountable respectfully and effectively. Sought out to lead initiatives where accountability has been lacking. Known for creating cultures where everyone owns their commitments and outcomes.' FROM capabilities WHERE name = 'Accountability' ON CONFLICT DO NOTHING;
INSERT INTO capability_levels (capability_id, level, description) SELECT id, 'foundational', 'Completes assigned tasks within reasonable timeframes. May struggle with prioritization or competing demands. Sometimes misses deadlines or needs extensions. Learning to estimate how long tasks will take. May get distracted or sidetracked easily. Uses basic tools (calendar, to-do lists) inconsistently. Relies on manager to help prioritize workload.' FROM capabilities WHERE name = 'Time Management' ON CONFLICT DO NOTHING;
