INSERT INTO capability_levels (capability_id, level, description) SELECT id, 'independent', 'Optimizes time to maximize productivity and impact. Prioritizes ruthlessly based on strategic value. Manages complex, competing priorities across multiple projects. Protects time for high-value activities. Delegates or declines low-value work appropriately. Maintains effectiveness even with heavy workload. Helps others improve their time management.' FROM capabilities WHERE name = 'Time Management' ON CONFLICT DO NOTHING;
INSERT INTO capability_levels (capability_id, level, description) SELECT id, 'mastery', 'Masters time as a strategic resource. Creates systems and norms that improve organizational productivity. Models time management that cascades through teams. Protects organizational focus on highest-value activities. Coaches leaders on strategic time management. Eliminates time-wasting practices at scale. Sought out for counsel on prioritization of major initiatives. Known for achieving extraordinary results through disciplined time management. Sets the standard for productivity and focus.' FROM capabilities WHERE name = 'Time Management' ON CONFLICT DO NOTHING;
