INSERT INTO capability_levels (capability_id, level, description) SELECT id, 'mastery', 'Sets organizational standards for quality and precision. Designs quality assurance systems used across the organization. Ensures detail excellence on the most critical work. Balances precision with innovation and risk-taking appropriately. Builds culture where quality is everyone''s responsibility. Coaches others on attention to detail without perfectionism. Prevents costly errors through systematic approaches. Sought out to review the most important deliverables. Known for setting the bar for excellence. Balances attention to detail with strategic thinking.' FROM capabilities WHERE name = 'Attention to Detail' ON CONFLICT DO NOTHING;
